  window.switchTab = function (tabId) {
    document.querySelectorAll("#u-workspace .tabpanel").forEach(function (p) {
      p.classList.toggle("active", p.id === tabId);
    });
    document.querySelectorAll("#u-workspace .wtab").forEach(function (t) {
      t.classList.toggle("active", t.getAttribute("data-tab") === tabId);
    });
    // make sure workspace screen is visible
    if (state.currentScreen !== "u-workspace") {
      document.querySelectorAll("#app-user .screen").forEach(function (s) {
        s.classList.toggle("active", s.id === "u-workspace");
      });
      state.currentScreen = "u-workspace";
    }
    window.scrollTo(0, 0);
  };

  window.switchCat = function (btn, panelId) {
    document.querySelectorAll("#a-catalogue .catpanel").forEach(function (p) {
      p.classList.toggle("active", p.id === panelId);
    });
    if (btn && btn.parentElement) {
      btn.parentElement.querySelectorAll(".wtab").forEach(function (b) { b.classList.remove("active"); });
      btn.classList.add("active");
    }
  };

